item.description:
处理边界条件？
循环不可靠！找到循环不变量！
#include &#34;../cunion.h&#34; class Solution { public: vector&lt;vector&lt;int&gt;&gt; generateMatrix(int n) { int num = 1; //注意这里是全闭区间 vector&lt;vector&lt;int&gt;&gt; matrix(n, vector&lt;int&gt;(n)); int left = 0, right = n - 1, top = 0, bottom = n - 1; while (left &lt;= right &amp;&amp; top &lt;= bottom) { //从左往右 for (int column = left; column &lt;= right; ++column) { matrix[top][column] = num; num++; } for (int row = top + 1; row &lt;= bottom; ++row) { matrix[row][right] = num; num++; } //从右往左 if (left &lt; right &amp;&amp; top &lt; bottom) { for (int column = right - 1; column &gt; left; --column) { matrix[bottom][column] = num; num++; } for (int row = bottom; row &gt; top; --row) { matrix[row][left] = num; num++; } } left++; right--; top++; bottom--; } return matrix; } }; int main() { Solution *solution; vector&lt;vector&lt;int&gt;&gt; vo = solution-&gt;generateMatrix(4); for (int i = 0; i &lt; vo.
